<?php

namespace App\Helpers;

class MenuHelper
{
    public static function getMainNavItems($user = null)
    {
        $items = [];

        // Dashboard — visible to all authenticated users
        $items[] = ['icon' => 'dashboard', 'name' => 'Dashboard', 'path' => route('dashboard')];

        // Projects — requires proyectos.ver
        if (!$user || $user->hasPermissionTo('proyectos.ver')) {
            $items[] = ['icon' => 'projects', 'name' => 'Proyectos', 'path' => route('proyectos')];
            $items[] = ['icon' => 'ai', 'name' => 'Requerimientos IA', 'path' => route('requerimientos.ia')];
        }

        // Clients — requires clientes.ver
        if (!$user || $user->hasPermissionTo('clientes.ver')) {
            $items[] = ['icon' => 'clients', 'name' => 'Clientes', 'path' => route('clientes')];
        }

        // Tasks — requires tareas.ver
        if (!$user || $user->hasPermissionTo('tareas.ver')) {
            $items[] = ['icon' => 'task', 'name' => 'Tareas', 'path' => route('tareas')];
        }

        // Pending items
        if (!$user || $user->hasPermissionTo('tareas.ver') || $user->hasPermissionTo('clientes.ver')) {
            $subItems = [];
            if (!$user || $user->hasPermissionTo('clientes.ver')) {
                $subItems[] = ['name' => 'Por Cliente',   'path' => route('pendientes.cliente')];
            }
            if (!$user || $user->hasPermissionTo('tareas.ver')) {
                $subItems[] = ['name' => 'Por Ingeniero', 'path' => route('pendientes.ingeniero')];
            }
            if (!empty($subItems)) {
                $items[] = ['icon' => 'pending', 'name' => 'Pendientes', 'subItems' => $subItems];
            }
        }

        // Meetings — requires tareas.ver
        if (!$user || $user->hasPermissionTo('tareas.ver')) {
            $items[] = ['icon' => 'calendar', 'name' => 'Reuniones', 'path' => route('reuniones')];
        }

        // Bonuses — only admin/gerente/super_admin
        if (!$user || $user->hasAnyRole(['super_admin', 'admin', 'gerente'])) {
            $items[] = ['icon' => 'bonus', 'name' => 'Bonos', 'path' => route('bonos')];
        }

        return $items;
    }

    public static function getOthersItems($user = null)
    {
        $items = [];

        // Reports — requires reportes.ver
        if (!$user || $user->hasPermissionTo('reportes.ver')) {
            $items[] = [
                'icon' => 'reports',
                'name' => 'Reportes',
                'subItems' => [
                    ['name' => 'Proyectos Activos', 'path' => route('reportes.activos')],
                    ['name' => 'Rendimiento',       'path' => route('reportes.rendimiento')],
                    ['name' => 'Bonos Generados',   'path' => route('reportes.bonos')],
                ],
            ];
        }

        // Users — requires usuarios.gestionar
        if (!$user || $user->hasPermissionTo('usuarios.gestionar')) {
            $items[] = ['icon' => 'users', 'name' => 'Usuarios', 'path' => route('usuarios')];
        }

        // Alerts — requires proyectos.ver
        if (!$user || $user->hasPermissionTo('proyectos.ver')) {
            $items[] = ['icon' => 'alerts', 'name' => 'Alertas', 'path' => route('alertas')];
        }

        // Config — only super_admin / admin
        if (!$user || $user->hasAnyRole(['super_admin', 'admin'])) {
            $items[] = ['icon' => 'authentication', 'name' => 'Configuración', 'path' => route('configuracion')];
        }

        return $items;
    }

    public static function getMenuGroups($user = null)
    {
        $groups = [];

        $mainItems = self::getMainNavItems($user);
        if (!empty($mainItems)) {
            $groups[] = ['title' => 'Principal', 'items' => $mainItems];
        }

        $adminItems = self::getOthersItems($user);
        if (!empty($adminItems)) {
            $groups[] = ['title' => 'Administración', 'items' => $adminItems];
        }

        return $groups;
    }

    public static function isActive($path)
    {
        return request()->is(ltrim($path, '/'));
    }

